        onChange={(v) => updateFixture({ depth: Math.max(50, u.fromDisplay(v)) })}
      />
      <InputField
        label="Rotation" type="number" suffix="°" step={15}
        value={fixture.rotation}
        onChange={(v) => updateFixture({ rotation: ((+v % 360) + 360) % 360 })}
      />
    </div>
  );
}

