116→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
117→  return {
118→    onMouseDown(modelPos, e, toolState) {
119→      if (e.button !== 0) return;
120→
121→      const floor = getFloor(activeFloorId);
122→      if (!floor) return;
123→
124→      // Check if clicking a handle
125→      const target = e.target;
126→      if (target.dataset.handle) {
127→        editorDispatch({
128→          type: 'UPDATE_TOOL_STATE',
129→          payload: {
130→            dragging: true,
131→            dragType: 'handle',
132→            handle: target.dataset.handle,
133→            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
134→            startPos: modelPos,
135→          },
136→        });
137→        return;
138→      }
139→
140→      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
141→      if (hit) {
142→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
143→        const draggableTypes = new Set(['wall', 'column', 'fixture', 'door', 'window', 'stair', 'sectionCut', 'landing']);
144→        if (!draggableTypes.has(hit.type)) return;
145→        editorDispatch({
146→          type: 'UPDATE_TOOL_STATE',
147→          payload: {
148→            dragging: true,
149→            dragType: 'move',
150→            startPos: modelPos,
151→            originalPos: modelPos,
152→          },
153→        });
154→      } else {
155→        editorDispatch({
156→          type: 'UPDATE_TOOL_STATE',
157→          payload: {
158→            dragging: true,
159→            dragType: 'marquee',
160→            startPos: modelPos,
161→            currentPos: modelPos,
162→          },
163→        });
164→      }
165→    },
166→
167→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
168→      if (toolState.dragging && toolState.dragType === 'marquee') {
169→        editorDispatch({
170→          type: 'UPDATE_TOOL_STATE',
171→          payload: { currentPos: modelPos },
172→        });
173→        return;
174→      }
175→
176→      if (!toolState.dragging || !selectedId) return;
177→
178→      const floor = getFloor(activeFloorId);
179→      if (!floor) return;
180→      const dx = modelPos.x - toolState.startPos.x;
181→      const dy = modelPos.y - toolState.startPos.y;
182→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
183→
184→      if (selectedType === 'wall') {
185→        const wall = floor.walls.find(w => w.id === selectedId);
186→        if (!wall) return;
187→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
188→
189→        if (toolState.dragType === 'handle') {
190→          const handle = toolState.handle;
191→          const oppositeKey = handle === 'start' ? 'end' : 'start';
192→          const oppositePoint = resolved[oppositeKey];
193→          let nextPoint = modelPos;
194→          let nextAttachment = null;
195→
196→          if (e.shiftKey) {
197→            const dx = modelPos.x - oppositePoint.x;
198→            const dy = modelPos.y - oppositePoint.y;
199→            const angle = Math.atan2(dy, dx);
200→            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
201→            const len = Math.sqrt(dx * dx + dy * dy);
202→            nextPoint = {
203→              x: oppositePoint.x + Math.cos(snapAngle) * len,
204→              y: oppositePoint.y + Math.sin(snapAngle) * len,
205→            };
206→          } else if (snapEnabled) {
207→            const snapResult = snapWallEndpoint(modelPos, {
208→              walls: floor.walls,
209→              columns: floor.columns || [],
210→              snapDist: snapDistModel,
211→              otherPoint: oppositePoint,
212→              ignoreWallId: wall.id,
213→            });
214→            if (snapResult) {
