276→        }
277→        editorDispatch({
278→          type: 'UPDATE_TOOL_STATE',
279→          payload: { startPos: modelPos },
280→        });
281→      } else if (selectedType === 'column') {
282→        const col = (floor.columns || []).find(c => c.id === selectedId);
