 36→export function clampWallOpeningOffset(length, width, offset) {
 37→  const safeLength = Math.max(0, Number(length) || 0);
 38→  const safeWidth = Math.max(0, Number(width) || 0);
 39→  const safeOffset = Number(offset) || 0;
 40→  const halfWidth = safeWidth / 2;
 41→
 42→  if (safeLength <= 0) return 0;
 43→  if (safeWidth >= safeLength) return safeLength / 2;
 44→
 45→  return Math.max(halfWidth, Math.min(safeLength - halfWidth, safeOffset));
 46→}
 47→
 48→export function positionOnWall(wall, offset) {
 49→  const dir = normalize(subtract(wall.end, wall.start));
 50→  return add(wall.start, scale(dir, offset));
 51→}
 52→
 53→export function wallDirection(wall) {
 54→  return normalize(subtract(wall.end, wall.start));
 55→}
 56→
 57→export function wallAngle(wall) {
 58→  const dx = wall.end.x - wall.start.x;
 59→  const dy = wall.end.y - wall.start.y;
 60→  return Math.atan2(dy, dx);
 61→}
